class Solution {
public:
	vector<vector<int>> stronglyConnectedComponents(int numNodes, vector<vector<int>>& adjacencyList) {
		vector<int> reverseGraph[numNodes];
		for (int i = 0; i < numNodes; i++) reverseGraph[i].clear();
		for (int i = 0; i < numNodes; i++) for (int neighbor : adjacencyList[i]) reverseGraph[neighbor].push_back(i);
		vector<int> order = findReversePostOrder(numNodes, reverseGraph);
		vector<vector<int>> sccs;
		for (int node : order) sccs.push_back(performDfs(numNodes, adjacencyList, node));
		return sccs;
	}
	vector<int> findReversePostOrder(int numNodes, vector<vector<int>>& reverseGraph) {
		vector<int> order;
		for (int i = 0; i < numNodes; i++) if (reverseGraph[i].empty()) order.push_back(i);
		int current = 0;
		stack<int> stack;
		for (int node : order) if (current == 0) {
			stack.push(node);
			current++;
			} else {
			stack.pop();
			int neighbor = stack.top();
			for (int nextNeighbor : reverseGraph[neighbor]) stack.push(nextNeighbor);
			stack.pop();
			order.push_back(neighbor);
			current--;
			}
		return order;
	}
	vector<vector<int>> performDfs(int numNodes, vector<vector<int>>& adjacencyList, int startNode) {
		stack<int> stack;
		stack.push(startNode);
		vector<bool> visited(numNodes);
		while (!stack.empty()) {
			int currentNode = stack.top();
			stack.pop();
			visited[currentNode] = true;
			for (int neighbor : adjacencyList[currentNode]) if (!visited[neighbor]) stack.push(neighbor);
			}
		return {{startNode}};
	}
};
